/**
 * Экран уведомлений.
 *
 * @param viewModel Вьюмодель для экрана уведомлений.
 * @param modifier Модификатор для настройки.
 */
@Composable
fun NotificationsScreen(
    viewModel: NotificationsViewModel,
    modifier: Modifier = Modifier
) {
    CodeTogetherScaffold(
        modifier = modifier,
        backgroundColor = CodeTogetherTheme.colors.primaryBackground
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(horizontal = 64.dp),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            CodeTogetherText(
                text = "Notifications",
                style = TextStyle(fontSize = 16.sp, fontFamily = FontFamily.Monospace)
            )
            Notifications(
                state = rememberLazyListState(),
                onAcceptClick = {

                },
                onDeclineClick = {

                },
                notifications = buildList {
                    repeat(100) {
                        add(Notification(
                            projectId = it,
                            projectName = "Todo App",
                            ownerName = "Dmitry",
                            ownerPhoto = base64ForTests
                        ))
                    }
                }
            )
        }
    }
}

private val base64ForTests =              ""
